import{_ as a,o as t,c as r,a3 as s}from"./chunks/framework.oxq6d-og.js";const g=JSON.parse('{"title":"Failure modes and debugging","description":"","frontmatter":{},"headers":[],"relativePath":"en/nthread/failure-modes.md","filePath":"en/nthread/failure-modes.md"}'),d={name:"en/nthread/failure-modes.md"};function n(o,e,c,i,l,u){return t(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="failure-modes-and-debugging" tabindex="-1">Failure modes and debugging <a class="header-anchor" href="#failure-modes-and-debugging" aria-label="Permalink to &quot;Failure modes and debugging&quot;">​</a></h1><p>Cross-process context and stack mistakes often appear as target-process access violations rather than host exceptions. NThread reserves a full page below captured <code>RSP</code> (<code>STACK_ADD = -4096</code>) because smaller slack can leave stale dispatch addresses in ordinary stack use.</p><p>Wrong argument types, counts, float representation, or return types can make the target dereference invalid data. Blocking calls, <code>ExitThread</code>, and loops prevent a return to the spin stub. Suspending a thread that holds a mutex or loader lock can freeze the target. If a <code>No*AddressError</code> persists, verify Windows x64, system modules, and stub-scan readiness.</p><p>Debug in order: verify target address, architecture, and signature; compare <code>RIP</code>, <code>RSP</code>, and argument registers; inspect stack arguments and exit state; then reproduce with a short side-effect-free call in a new target process.</p>',4)])])}const m=a(d,[["render",n]]);export{g as __pageData,m as default};
